const fs = require('fs');
const body = $input.first().json.body || $input.first().json;
const description = (body.description || '').trim();
const channelId   = body.channelId || '';
const userId      = body.userId || '';
const userName    = body.userName || 'user';
// Sanitize jobId: only 8 lowercase hex chars
const jobId      = (body.jobId || '').toString().replace(/[^a-f0-9]/gi, '').slice(0, 8).toLowerCase();
const inlineCode = (body.inlineCode || '').trim();

const BASE_SYSTEM = `You are an expert OpenSCAD programmer who creates parametric 3D-printable models.

OUTPUT RULES \u2014 follow exactly:
1. Output ONLY valid OpenSCAD code. Absolutely no markdown, no explanations, no extra text.
2. Declare all dimensions as named variables at the top (in mm).
3. Add brief inline comments on each major section.
4. The model MUST be genuinely 3D \u2014 it must have real volume in X, Y, and Z.
5. Center the finished model at the origin.

MANDATORY 3D REQUIREMENTS:
- NEVER produce a flat 2D shape as the final output.
- Solid primitives: cube(), sphere(), cylinder() \u2014 always in proper 3D context.
- For extruded cross-sections (e.g. brackets, rails): use linear_extrude(height=H) on a 2D polygon/square/circle.
- For rotational parts (gears, rings, wheels, pulleys): use rotate_extrude() around the Z axis on a 2D profile drawn in the XY plane.
- Minimum feature height: 5 mm unless the user specifies otherwise.
- Use difference() for subtractive geometry (holes, cutouts), union() for additive joins.
- $fn \u2265 64 for all circles and cylinders.

QUALITY:
- The model must be manifold/watertight (no self-intersections).
- Design for printability: avoid unsupported overhangs > 45\u00b0 unless support is described.
- All variables at the top; no magic numbers buried in geometry.`;

let systemPrompt, userMessage;

if (jobId) {
  const scadPath = `/home/node/ai-output/3d/${jobId}/model.scad`;
  let existingCode = '';
  try { existingCode = fs.readFileSync(scadPath, 'utf8'); } catch(e) {}

  if (existingCode) {
    systemPrompt = BASE_SYSTEM + `\n\nIMPROVEMENT MODE:\nApply ONLY the requested improvements while preserving the overall structure and variable naming.\nReturn the complete updated OpenSCAD code (not just the changed sections).`;
    userMessage = `Improve this OpenSCAD model with: ${description}\n\nEXISTING CODE (job ${jobId}):\n${existingCode}`;
  } else {
    // jobId provided but file not found \u2014 fall back to new generation
    systemPrompt = BASE_SYSTEM;
    userMessage = `Generate OpenSCAD code for: ${description}`;
  }
} else if (inlineCode) {
  systemPrompt = BASE_SYSTEM + `\n\nIMPROVEMENT MODE:\nApply ONLY the requested improvements while preserving the overall structure and variable naming.\nReturn the complete updated OpenSCAD code (not just the changed sections).`;
  userMessage = `Improve this OpenSCAD model with: ${description}\n\nEXISTING CODE:\n${inlineCode}`;
} else {
  systemPrompt = BASE_SYSTEM;
  userMessage = `Generate OpenSCAD code for: ${description}`;
}

return [{ json: { description, channelId, userId, userName, systemPrompt, userMessage, jobId } }];

// $input.first().json IS the already-parsed Ollama JSON response
const resp = $input.first().json;
const raw = resp.message?.content || resp.response || '';

// Strip markdown fences if Ollama wrapped it anyway
let code = raw.trim();
const fenceMatch = code.match(/```(?:openscad|scad)?\n([\s\S]*?)```/i);
if (fenceMatch) code = fenceMatch[1].trim();

// Pull context from Build Prompt node (HTTP Request replaced our json)
const buildData = $('Build Prompt').first().json;

return [{ json: {
  code,
  description: buildData.description || '',
  channelId: buildData.channelId || '',
  userId: buildData.userId || '',
  userName: buildData.userName || 'user',
} }];

const render = $input.first().json;
const codeData = $('Extract Code').first().json;

const code        = codeData.code || '';
const description = codeData.description || '';
const channelId   = codeData.channelId || '';
const success     = render.success || false;
const jobId       = render.job_id || '';
const stlPath     = render.stl_path || null;
const pngB64      = render.png_b64 || null;

return [{ json: { code, description, channelId, success, jobId, stlPath, pngB64 } }];

const prev = $input.first().json;
const pngB64 = prev.pngB64 || null;

// Build binary item from base64 if we have a PNG
const result = { json: prev };
if (pngB64) {
  result.binary = {
    data: {
      data: pngB64,
      mimeType: 'image/png',
      fileName: '3d-preview.png',
      fileSize: Math.ceil(pngB64.length * 0.75),
    }
  };
}
return [result];

