={{ (() => {
  const d = $input.first().json;
  const channelId   = d.channelId || '';
  const description = d.description || '';
  const stlPath     = d.stlPath || null;
  const code        = d.code || '';
  const jobId       = d.jobId || '';
  const success     = d.success !== false;
  const imageUrl = jobId ? 'https://appendicular-wilson-looser.ngrok-free.dev/webhook/preview-3d?job=' + jobId : null;

  const scadPath = stlPath ? stlPath.replace(/\.stl$/, '.scad') : null;
  const codeSnip = code.length > 2600
    ? code.slice(0, 2600) + '\n// ... (full code saved at ' + (scadPath || 'server') + ')'
    : code;

  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: ':triangular_ruler: 3D Model Generated', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*' + description + '*' } },
  ];

  if (imageUrl) {
    blocks.push({ type: 'image', image_url: imageUrl, alt_text: '3D model preview' });
  }

  blocks.push({ type: 'divider' });

  if (stlPath) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':white_check_mark: *STL:* `' + stlPath + '`\n_Slice in PrusaSlicer / Bambu Studio / Cura to print_' } });
  }
  if (!success) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':warning: *Render warning* — check the code manually in OpenSCAD' } });
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*OpenSCAD source:*\n```\n' + codeSnip + '\n```' } });
  const hint = jobId
    ? `:pencil: Paste code into OpenSCAD to edit · _Job: \`${jobId}\` · Improve with \`/3d improve ${jobId} <changes>\`_`
    : ':pencil: Paste code into OpenSCAD to edit';
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: hint }] });

  return JSON.stringify({ channel: channelId, blocks, unfurl_links: false });
})() }}

